class DataTableBuilder{constructor(){}static initModalDataTable(n,t){$(n).find(".datagrid").each(function(n,i){if($(i).attr("id")!==undefined&&$(i).attr("id")!=null){var r=new DataTableInitializer($(i),t);r.JqueryDataTableInit()}})}static init(n){$(n).find(".datagrid").each(function(n,t){if($(t).attr("id")!==undefined&&$(t).attr("id")!=null){var i=new DataTableInitializer($(t),null);i.JqueryDataTableInit()}})}static initDocument(){$(document).find(".datagrid").each(function(n,t){if($(t).attr("id")!==undefined&&$(t).attr("id")!=null){var i=new DataTableInitializer($(t),null);i.JqueryDataTableInit()}})}}